def verify(output: str):
    # Validate basic format: must be exactly 20 decimal digits
    if not isinstance(output, str) or len(output) != 20 or not output.isdigit():
        message = "Output is not a string of exactly 20 decimal digits"
        return (False, 0.0, message)

    constraints_satisfied = 0
    total_constraints = 5
    failed_constraints = []

    # Constraint 1: The string contains exactly 1 occurrence of the substring "2026"
    count_2026 = output.count("2026")
    if count_2026 == 1:
        constraints_satisfied += 1
    else:
        failed_constraints.append(f"exactly 1 occurrence of '2026' (found {count_2026})")

    # Constraint 2: The string contains no occurrence of "000"
    if "000" not in output:
        constraints_satisfied += 1
    else:
        failed_constraints.append("no occurrence of '000' (found at least one)")

    # Constraint 3: The string must not start with '0'
    if output[0] != '0':
        constraints_satisfied += 1
    else:
        failed_constraints.append("not starting with '0' (starts with '0')")

    # Constraint 4: The string must end with an odd digit
    odd_digits = {'1', '3', '5', '7', '9'}
    if output[-1] in odd_digits:
        constraints_satisfied += 1
    else:
        failed_constraints.append("ending with an odd digit (ends with '" + output[-1] + "')")

    # Constraint 5: The total number of even digits is exactly 10
    even_digits = {'0', '2', '4', '6', '8'}
    even_count = sum(1 for c in output if c in even_digits)
    if even_count == 10:
        constraints_satisfied += 1
    else:
        failed_constraints.append(f"exactly 10 even digits (found {even_count})")

    # Calculate score
    score = constraints_satisfied / total_constraints

    # Generate message
    if constraints_satisfied == total_constraints:
        message = "All constraints satisfied"
    else:
        message = "Constraints failed: " + "; ".join(failed_constraints)

    return (constraints_satisfied == total_constraints, score, message)
